styles:
:root {
      --bg: #ffffff;
      --bg-alt: #f7f9fc;
      --text: #0b0e14;
      --text-soft: #545b68;
      --border: #e6e9ef;
      --blue: #2457ec;
      --blue-deep: #163b9e;
      --teal: #0fae8b;
      --teal-soft: #e6f7f2;
      --blue-soft: #eaf0ff;
    }

    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    html {
      scroll-behavior: smooth;
    }

    body {
      background: var(--bg);
      color: var(--text);
      font-family: 'DM Sans', sans-serif;
      line-height: 1.6;
      -webkit-font-smoothing: antialiased;
    }

    h1,
    h2,
    h3,
    h4 {
      font-family: 'Sora', sans-serif;
      font-weight: 600;
      color: var(--text);
      letter-spacing: -0.02em;
    }

    .mono {
      font-family: 'JetBrains Mono', monospace;
    }

    p {
      text-align: justify;
    }

    a {
      color: inherit;
      text-decoration: none;
    }

    ul {
      list-style: none;
    }

    .wrap {
      max-width: 1180px;
      margin: 0 auto;
      padding: 0 32px;
    }

    /* ===== NAV ===== */
    header {
      position: sticky;
      top: 0;
      z-index: 100;
      background: rgba(255, 255, 255, 0.85);
      backdrop-filter: blur(10px);
      border-bottom: 1px solid var(--border);
    }

    nav {
      display: flex;
      align-items: center;
      justify-content: space-between;
      max-width: 1180px;
      margin: 0 auto;
      padding: 18px 32px;
    }

    .logo {
      font-family: 'Sora', sans-serif;
      font-weight: 700;
      font-size: 20px;
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .logo .dot {
      width: 9px;
      height: 9px;
      border-radius: 50%;
      background: var(--teal);
      display: inline-block;
    }

    .nav-links {
      display: flex;
      gap: 36px;
      align-items: center;
    }

    .nav-links a {
      font-size: 14px;
      font-weight: 500;
      color: var(--text-soft);
      position: relative;
      padding: 4px 0;
      transition: color .2s;
    }

    .nav-links a:hover {
      color: var(--blue);
    }

    .nav-links a::after {
      content: '';
      position: absolute;
      left: 0;
      bottom: -4px;
      height: 2px;
      width: 0;
      background: var(--blue);
      transition: width .25s;
    }

    .nav-links a:hover::after {
      width: 100%;
    }

    .nav-links a.nav-cta::after {
      display: none;
    }

    .nav-links a.nav-cta {
      background: var(--text);
      color: #fff !important;
      padding: 14px 30px;
      border-radius: 100px;
      font-size: 14px;
      font-weight: 600;
      letter-spacing: 0.01em;
      line-height: 1;
      transition: background .2s, transform .2s;
    }

    .nav-links a.nav-cta:hover {
      background: var(--blue);
      transform: translateY(-1px);
    }

    .menu-btn {
      display: none;
      flex-direction: column;
      gap: 4px;
      cursor: pointer;
      background: none;
      border: none;
    }

    .menu-btn span {
      width: 22px;
      height: 2px;
      background: var(--text);
    }

    /* ===== HERO ===== */
    .hero {
      padding: 96px 0 100px;
      position: relative;
      overflow: hidden;
    }

    .hero .wrap {
      display: grid;
      grid-template-columns: 1.15fr 0.85fr;
      gap: 56px;
      align-items: center;
    }

    .eyebrow {
      display: inline-flex;
      align-items: center;
      gap: 8px;
      font-family: 'JetBrains Mono', monospace;
      font-size: 12.5px;
      color: var(--blue-deep);
      background: var(--blue-soft);
      border: 1px solid #d7e2ff;
      padding: 6px 14px;
      border-radius: 100px;
      margin-bottom: 22px;
    }

    .eyebrow .pulse {
      width: 7px;
      height: 7px;
      border-radius: 50%;
      background: var(--teal);
      box-shadow: 0 0 0 0 rgba(15, 174, 139, .5);
      animation: pulse 2s infinite;
    }

    @keyframes pulse {
      0% {
        box-shadow: 0 0 0 0 rgba(15, 174, 139, .5);
      }

      70% {
        box-shadow: 0 0 0 8px rgba(15, 174, 139, 0);
      }

      100% {
        box-shadow: 0 0 0 0 rgba(15, 174, 139, 0);
      }
    }

    .hero h1 {
      font-size: clamp(38px, 5vw, 60px);
      line-height: 1.05;
      margin-bottom: 20px;
    }

    .hero h1 .accent {
      color: var(--blue);
    }

    .hero p.lead {
      font-size: 17px;
      color: var(--text-soft);
      max-width: 520px;
      margin-bottom: 32px;
    }

    .hero-btns {
      display: flex;
      gap: 14px;
      flex-wrap: wrap;
      margin-bottom: 36px;
    }

    .btn {
      display: inline-flex;
      align-items: center;
      gap: 8px;
      padding: 13px 24px;
      border-radius: 100px;
      font-size: 14.5px;
      font-weight: 600;
      border: 1px solid transparent;
      cursor: pointer;
      transition: all .2s;
    }

    .btn-primary {
      background: var(--blue);
      color: #fff;
    }

    .btn-primary:hover {
      background: var(--blue-deep);
      transform: translateY(-2px);
    }

    .btn-outline {
      background: transparent;
      color: var(--text);
      border-color: var(--border);
    }

    .btn-outline:hover {
      border-color: var(--text);
      transform: translateY(-2px);
    }

    .hero-meta {
      display: flex;
      gap: 28px;
      flex-wrap: wrap;
    }

    .hero-meta div {
      border-left: 2px solid var(--teal);
      padding-left: 12px;
    }

    .hero-meta .num {
      font-family: 'Sora';
      font-size: 22px;
      font-weight: 700;
    }

    .hero-meta .label {
      font-size: 12px;
      color: var(--text-soft);
    }

    .photo-frame {
      position: relative;
      width: 100%;
      max-width: 420px;
      margin: 0 auto;
      display: flex;
      align-items: center;
      justify-content: center;
      opacity: 0;
      animation: frameIn .9s cubic-bezier(.16, 1, .3, 1) .15s forwards;
    }

    @keyframes frameIn {
      from {
        opacity: 0;
        transform: translateY(24px) scale(.96);
      }

      to {
        opacity: 1;
        transform: translateY(0) scale(1);
      }
    }

    .photo-box {
      position: relative;
      width: 300px;
      height: 370px;
      flex-shrink: 0;
    }

    /* soft rotating glow behind the subject */
    .photo-box::before {
      content: '';
      position: absolute;
      inset: -18px;
      z-index: -1;
      border-radius: 50%;
      background: conic-gradient(from 0deg,
          rgba(36, 87, 236, .28),
          rgba(15, 174, 139, .28),
          rgba(240, 166, 58, .22),
          rgba(36, 87, 236, .28));
      filter: blur(38px);
      opacity: .8;
      animation: glowSpin 10s linear infinite, glowPulse 4s ease-in-out infinite;
    }

    @keyframes glowSpin {
      to {
        transform: rotate(360deg);
      }
    }

    @keyframes glowPulse {

      0%,
      100% {
        opacity: .6;
      }

      50% {
        opacity: .95;
      }
    }

    .photo-box img.profile-img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      object-position: top center;
      display: block;
      /* remove all box styling — show plain PNG */
      background: transparent;
      border: none;
      border-radius: 0;
      /* subtle drop-shadow to lift person off page, gently animated */
      filter: drop-shadow(0 20px 40px rgba(20, 30, 60, 0.12));
      animation: profileBreathe 5s ease-in-out infinite;
      transition: filter .3s ease, transform .3s ease;
    }

    .photo-box:hover img.profile-img {
      transform: translateY(-4px) scale(1.015);
      filter: drop-shadow(0 26px 46px rgba(20, 30, 60, 0.18));
    }

    @keyframes profileBreathe {

      0%,
      100% {
        transform: translateY(0);
      }

      50% {
        transform: translateY(-6px);
      }
    }

    /* fallback only shown when no image at all */
    .photo-fallback {
      display: none;
      flex-direction: column;
      align-items: center;
      gap: 10px;
      color: var(--blue-deep);
      width: 300px;
      height: 370px;
      justify-content: center;
    }

    .photo-fallback .initials {
      font-family: 'Sora';
      font-weight: 700;
      font-size: 64px;
      color: var(--blue);
    }

    .photo-fallback small {
      font-size: 12px;
      color: var(--text-soft);
      max-width: 200px;
      text-align: center;
      font-family: 'JetBrains Mono';
    }

    /* === floating tech badges === */
    .tech-badge {
      position: absolute;
      z-index: 2;
      background: #fff;
      border: 1px solid var(--border);
      border-radius: 14px;
      padding: 10px 14px;
      font-size: 12px;
      font-weight: 600;
      font-family: 'JetBrains Mono', monospace;
      box-shadow: 0 8px 24px rgba(20, 30, 60, .10);
      display: flex;
      align-items: center;
      gap: 7px;
      white-space: nowrap;
      color: var(--text);
      opacity: 0;
      cursor: default;
      transition: transform .25s ease, box-shadow .25s ease;
    }

    .tech-badge:hover {
      transform: translateY(-4px) scale(1.06) !important;
      z-index: 5;
      background: var(--tone-bg, #fff);
      border-color: var(--tone-border, var(--border));
      color: var(--tone-text, var(--text));
      box-shadow: 0 16px 34px var(--tone-shadow, rgba(20, 30, 60, .18)) !important;
    }

    .tech-badge .badge-dot {
      width: 8px;
      height: 8px;
      border-radius: 50%;
      flex-shrink: 0;
      animation: dotBlink 2.4s ease-in-out infinite;
    }

    @keyframes dotBlink {

      0%,
      100% {
        opacity: 1;
      }

      50% {
        opacity: .35;
      }
    }

    .tb-1 {
      top: 10%;
      left: -30px;
      animation: badgeIn .6s cubic-bezier(.16, 1, .3, 1) .5s forwards,
        floatBadge 3.2s ease-in-out 1.1s infinite alternate;
    }

    .tb-2 {
      top: 42%;
      left: -50px;
      animation: badgeIn .6s cubic-bezier(.16, 1, .3, 1) .7s forwards,
        floatBadge 2.8s ease-in-out 1.3s infinite alternate-reverse;
    }

    .tb-3 {
      bottom: 18%;
      left: -20px;
      animation: badgeIn .6s cubic-bezier(.16, 1, .3, 1) .9s forwards,
        floatBadge 3.6s ease-in-out 1.5s infinite alternate;
    }

    .tb-4 {
      top: 8%;
      right: -30px;
      animation: badgeIn .6s cubic-bezier(.16, 1, .3, 1) .6s forwards,
        floatBadge 3.0s ease-in-out 1.2s infinite alternate-reverse;
    }

    .tb-5 {
      bottom: 22%;
      right: -40px;
      animation: badgeIn .6s cubic-bezier(.16, 1, .3, 1) .8s forwards,
        floatBadge 2.6s ease-in-out 1.4s infinite alternate;
    }

    @keyframes badgeIn {
      from {
        opacity: 0;
        transform: translateY(10px) scale(.85);
      }

      to {
        opacity: 1;
        transform: translateY(0) scale(1);
      }
    }

    @keyframes floatBadge {
      0% {
        transform: translateY(0px) rotate(0deg);
      }

      100% {
        transform: translateY(-10px) rotate(-2deg);
      }
    }

    /* location tag */
    .photo-tag {
      position: absolute;
      bottom: -30px;
      left: 50%;
      transform: translateX(-50%);
      background: #fff;
      border: 1px solid var(--border);
      padding: 10px 18px;
      border-radius: 100px;
      font-family: 'JetBrains Mono';
      font-size: 12px;
      box-shadow: 0 10px 30px rgba(20, 30, 60, .10);
      white-space: nowrap;
    }

    .photo-tag b {
      color: var(--teal);
    }

    /* ===== SECTION HEADERS ===== */
    .section {
      padding: 88px 0;
    }

    .section-alt {
      background: var(--bg-alt);
    }

    .section-head {
      margin-bottom: 48px;
      max-width: 640px;
    }

    .section-tag {
      font-family: 'JetBrains Mono';
      font-size: 12.5px;
      color: var(--teal);
      display: flex;
      align-items: center;
      gap: 10px;
      margin-bottom: 14px;
    }

    .section-tag::before {
      content: '';
      width: 24px;
      height: 1px;
      background: var(--teal);
    }

    .section-head h2 {
      font-size: clamp(28px, 3.4vw, 38px);
    }

    .section-head p {
      color: var(--text-soft);
      margin-top: 12px;
      font-size: 15.5px;
    }

    /* ===== ABOUT ===== */
    .about-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 60px;
    }

    .about-grid p {
      color: var(--text-soft);
      margin-bottom: 16px;
      font-size: 15.5px;
    }

    .about-grid p b {
      color: var(--text);
      font-weight: 600;
    }

    .info-list {
      display: grid;
      gap: 14px;
      margin-top: 24px;
    }

    .info-list li {
      display: flex;
      justify-content: space-between;
      border-bottom: 1px dashed var(--border);
      padding-bottom: 12px;
      font-size: 14.5px;
    }

    .info-list li span:first-child {
      color: var(--text-soft);
      font-family: 'JetBrains Mono';
      font-size: 12.5px;
    }

    .info-list li span:last-child {
      font-weight: 600;
    }

    .subhead {
      font-family: 'Sora';
      font-weight: 600;
      font-size: 18px;
      margin: 36px 0 16px;
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .subhead .sq {
      width: 8px;
      height: 8px;
      background: var(--blue);
    }

    .timeline {
      display: grid;
      gap: 22px;
    }

    .tl-item {
      border-left: 2px solid var(--border);
      padding-left: 20px;
      position: relative;
    }

    .tl-item::before {
      content: '';
      position: absolute;
      left: -6px;
      top: 4px;
      width: 10px;
      height: 10px;
      border-radius: 50%;
      background: var(--teal);
      border: 2px solid #fff;
    }

    .tl-item h4 {
      font-size: 15.5px;
      margin-bottom: 4px;
    }

    .tl-item .tl-org {
      font-size: 13px;
      color: var(--blue);
      font-family: 'JetBrains Mono';
      margin-bottom: 6px;
    }

    .tl-item p {
      font-size: 14px;
      color: var(--text-soft);
    }

    .award-badge {
      display: inline-block;
      font-size: 11px;
      font-family: 'JetBrains Mono';
      background: var(--teal-soft);
      color: var(--teal);
      padding: 3px 10px;
      border-radius: 100px;
      margin-top: 8px;
    }

    .explore-btn {
      display: inline-flex;
      align-items: center;
      margin-top: 14px;
      padding: 6px 14px;
      font-size: 11.5px;
      font-family: 'JetBrains Mono', monospace;
      font-weight: 600;
      color: var(--blue);
      background: transparent;
      border: 1px solid var(--blue);
      border-radius: 100px;
      text-decoration: none;
      transition: all .2s;
    }

    .explore-btn:hover {
      background: var(--blue-soft);
      transform: translateX(4px);
    }

    /* ===== MARQUEE SKILLS ===== */
    .marquee-wrap {
      display: flex;
      flex-direction: column;
      gap: 16px;
      margin-top: 20px;
      -webkit-mask-image: linear-gradient(90deg, transparent, #000 8%, #000 92%, transparent);
      mask-image: linear-gradient(90deg, transparent, #000 8%, #000 92%, transparent);
    }

    .marquee-row {
      overflow: hidden;
      width: 100%;
    }

    .marquee-track {
      display: flex;
      gap: 14px;
      width: max-content;
      animation: scrollLeft 38s linear infinite;
    }

    .marquee-row.reverse .marquee-track {
      animation: scrollRight 34s linear infinite;
    }

    @keyframes scrollLeft {
      from {
        transform: translateX(0);
      }

      to {
        transform: translateX(-50%);
      }
    }

    @keyframes scrollRight {
      from {
        transform: translateX(-50%);
      }

      to {
        transform: translateX(0);
      }
    }

    .chip {
      display: flex;
      align-items: center;
      gap: 8px;
      background: #fff;
      border: 1px solid var(--border);
      padding: 11px 18px;
      border-radius: 12px;
      font-size: 14px;
      font-weight: 500;
      white-space: nowrap;
      box-shadow: 0 2px 8px rgba(20, 30, 60, .03);
    }

    .chip .cdot {
      width: 6px;
      height: 6px;
      border-radius: 50%;
    }

    .chip:nth-child(4n+1) .cdot {
      background: var(--blue);
    }

    .chip:nth-child(4n+2) .cdot {
      background: var(--teal);
    }

    .chip:nth-child(4n+3) .cdot {
      background: #f0a63a;
    }

    .chip:nth-child(4n+4) .cdot {
      background: #c15adf;
    }

    .marquee-wrap:hover .marquee-track {
      animation-play-state: paused;
    }

    /* ===== PROJECTS ===== */
    .proj-grid {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 22px;
    }

    .proj-card {
      background: #fff;
      border: 1px solid var(--border);
      border-radius: 18px;
      padding: 26px;
      display: flex;
      flex-direction: column;
      gap: 12px;
      transition: transform .25s, box-shadow .25s, border-color .25s;
    }

    .proj-card:hover {
      transform: translateY(-6px);
      box-shadow: 0 18px 40px rgba(20, 30, 60, .08);
      border-color: var(--blue);
    }

    .proj-img {
      width: 100%;
      aspect-ratio: 16/9;
      border-radius: 12px;
      overflow: hidden;
      background: linear-gradient(135deg, var(--blue-soft), var(--teal-soft));
      border: 1px solid var(--border);
      position: relative;
      display: flex;
      align-items: center;
      justify-content: center;
    }

    .proj-img::before {
      content: '</>';
      font-family: 'JetBrains Mono', monospace;
      font-size: 18px;
      font-weight: 600;
      color: var(--blue);
      opacity: 0.35;
    }

    .proj-img img {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      object-fit: cover;
      transition: transform .3s ease;
    }

    .proj-card:hover .proj-img img {
      transform: scale(1.05);
    }

    .proj-top {
      display: flex;
      justify-content: space-between;
      align-items: flex-start;
    }

    .proj-num {
      font-family: 'JetBrains Mono';
      font-size: 12px;
      color: var(--text-soft);
    }

    .proj-card h3 {
      font-size: 16.5px;
      line-height: 1.3;
    }

    .proj-card .proj-sub {
      font-size: 12px;
      color: var(--blue);
      font-family: 'JetBrains Mono';
    }

    .proj-card p {
      font-size: 13.5px;
      color: var(--text-soft);
      flex-grow: 1;
    }

    .proj-tags {
      display: flex;
      flex-wrap: wrap;
      gap: 6px;
      margin-top: 6px;
    }

    .proj-tags span {
      font-size: 10.5px;
      font-family: 'JetBrains Mono';
      color: var(--blue-deep);
      background: var(--blue-soft);
      padding: 4px 9px;
      border-radius: 100px;
    }

    /* ===== CERTIFICATIONS ===== */
    .cert-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
      gap: 20px;
    }

    .cert-card {
      background: #fff;
      border: 1px solid var(--border);
      border-radius: 16px;
      padding: 20px;
      display: flex;
      align-items: flex-start;
      gap: 16px;
      transition: transform .25s, box-shadow .25s, border-color .25s;
    }

    .cert-card:hover {
      transform: translateY(-4px);
      box-shadow: 0 12px 24px rgba(20, 30, 60, .06);
      border-color: var(--blue);
    }

    .cert-icon {
      width: 48px;
      height: 48px;
      border-radius: 12px;
      background: var(--blue-soft);
      color: var(--blue);
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 24px;
      flex-shrink: 0;
    }

    .cert-info h3 {
      font-size: 15px;
      line-height: 1.3;
      margin-bottom: 4px;
      color: var(--text);
    }

    .cert-info p {
      font-size: 13px;
      color: var(--text-soft);
      font-family: 'JetBrains Mono', monospace;
    }

    .cert-card a {
      text-decoration: none;
      display: flex;
      align-items: flex-start;
      gap: 16px;
      width: 100%;
    }

    .proj-links {
      display: flex;
      gap: 8px;
      flex-wrap: wrap;
      margin-top: 10px;
    }

    .proj-links a {
      display: inline-flex;
      align-items: center;
      gap: 6px;
      font-size: 12.5px;
      font-family: 'JetBrains Mono', monospace;
      font-weight: 600;
      color: #fff;
      background: var(--text);
      padding: 8px 16px;
      border-radius: 100px;
      transition: background .2s, transform .2s;
      text-decoration: none;
    }

    .proj-links a:hover {
      background: var(--blue);
      transform: translateY(-2px);
    }

    .proj-links a svg {
      width: 14px;
      height: 14px;
      fill: currentColor;
    }

    /* ===== CV ===== */
    .cv-panel {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 0;
      border: 1px solid var(--border);
      border-radius: 24px;
      overflow: hidden;
      background: #fff;
    }

    .cv-left {
      padding: 56px;
      display: flex;
      flex-direction: column;
      justify-content: center;
      gap: 20px;
    }

    .cv-left h3 {
